diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 24a166906f1f..897587b3cbd0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1225,6 +1225,7 @@ static Instruction *combineAddSubWithShlAddSub(InstCombiner::BuilderTy &Builder,
 }

 /// Try to reduce signed division by power-of-2 to an arithmetic shift right.
+
 static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Division must be by power-of-2, but not the minimum signed value.
   Value *X;
@@ -1235,24 +1236,43 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {

   // Rounding is done by adding -1 if the dividend (X) is negative and has any
   // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
-  // sext (icmp ugt (X & (DivC - 1)), SMIN)
+  // sext (icmp ugt (X & (SMin | (DivC - 1)), SMIN)
+  // For DivC == 2, an alternative pattern is:
+  // sext (icmp eq (X & (SMin | (DivC - 1)), SMin | (DivC - 1))
   const APInt *MaskC;
   ICmpInst::Predicate Pred;
+  const APInt *CmpRHSC;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_APInt(CmpRHSC)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
-  if (*MaskC != (SMin | (*DivC - 1)))
+  APInt ExpectedMask = SMin | (*DivC - 1);
+
+  if (*MaskC != ExpectedMask)
+    return nullptr;
+
+  if (Pred == ICmpInst::ICMP_UGT) {
+    // Canonical pattern: sext (icmp ugt (X & ExpectedMask), SMin)
+    if (*CmpRHSC != SMin)
+      return nullptr;
+  } else if (Pred == ICmpInst::ICMP_EQ) {
+    // Alternative pattern for DivC == 2: sext (icmp eq (X & ExpectedMask), ExpectedMask)
+    // This is only valid when DivC == 2 because the mask has only one low bit,
+    // making the equality check equivalent to "at least one low bit set".
+    if (*DivC != 2 || *CmpRHSC != ExpectedMask)
+      return nullptr;
+  } else {
     return nullptr;
+  }

   // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
   return BinaryOperator::CreateAShr(
       X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
 }

+
 Instruction *InstCombinerImpl::
     canonicalizeCondSignextOfHighBitExtractToSignextHighBitExtract(
         BinaryOperator &I) {

